def _register_heif_opener() -> None:
    global _HEIF_REGISTERED
    if _HEIF_REGISTERED:
        return
    try:
        import pillow_heif
    except ImportError as error:
        raise HeicCodecError(
            "HEIC support requires pillow-heif. Install pillow-heif in the server environment."
        ) from error
    pillow_heif.register_heif_opener()
    _HEIF_REGISTERED = True

