def _raster_from_image(image) -> Raster:
    if image.mode in {"RGBA", "LA"} or (image.mode == "P" and "transparency" in image.info):
        rgba = image.convert("RGBA")
        return Raster(rgba.width, rgba.height, 4, bytearray(rgba.tobytes()))
    rgb = image.convert("RGB")
    return Raster(rgb.width, rgb.height, 3, bytearray(rgb.tobytes()))

