def decode_heic(data: bytes) -> Raster:
    if not is_heic_container(data):
        raise HeicCodecError("Not a HEIC/HEIF image.")
    try:
        inspect_heic_container(data)
    except HeicBoxError as error:
        raise HeicCodecError(str(error)) from error

    Image = _require_pillow_image()
    try:
        with Image.open(io.BytesIO(data)) as image:
            image.load()
            if image.format not in {"HEIF", "HEIC", "AVIF"}:
                raise HeicCodecError("Payload is not a valid HEIC/HEIF image.")
            return _raster_from_image(image)
    except HeicCodecError:
        raise
    except OSError as error:
        raise HeicCodecError(f"Could not decode HEIC image: {error}") from error

