def encode_heic(raster: Raster, quality: int = 80) -> bytes:
    Image = _require_pillow_image()
    quality = max(1, min(100, int(quality)))
    buffer = io.BytesIO()
    if raster.channels == 4:
        image = Image.frombytes("RGBA", (raster.width, raster.height), bytes(raster.data))
    else:
        image = Image.frombytes(
            "RGB",
            (raster.width, raster.height),
            bytes(raster.to_rgb().data),
        )
    try:
        image.save(
            buffer,
            format="HEIF",
            quality=quality,
        )
    except OSError as error:
        raise HeicCodecError(f"Could not encode HEIC image: {error}") from error
    output = buffer.getvalue()
    if not is_heic_container(output):
        raise HeicCodecError("HEIC encoder produced an invalid container.")
    return output
